1	import { readFileSync } from "node:fs";
2	import { quote, claim, cap, isKnownItemType, type Item } from "./claim-office.js";
3	
4	type QuoteStep = { op: "quote"; items: Item[] };
5	type ClaimStep = { op: "claim"; policy: number; incident: { cause: string; damages: { itemType: string; amount: number }[] } };
6	type Step = QuoteStep | ClaimStep;
7	
8	type Scenario = {
9	  customer: { yearsWithMHPCO: number };
10	  steps: Step[];
11	};
12	
13	type Policy = { items: Item[]; remainingCap: number };
14	type StepResult = Record<string, number>;
15	
16	type ScenarioState = {
17	  customer: { yearsWithMHPCO: number };
18	  policies: Policy[];
19	  previousContracts: number;
20	};
21	
22	const handleQuoteStep = (state: ScenarioState, step: QuoteStep): StepResult => {
23	  const premium = quote({
24	    customer: {
25	      yearsWithMHPCO: state.customer.yearsWithMHPCO,
26	      previousContracts: state.previousContracts,
27	    },
28	    items: step.items,
29	  });
30	  state.policies.push({ items: step.items, remainingCap: cap(step.items) });
31	  state.previousContracts += 1;
32	  return { premium };
33	};
34	
35	const findDamageNotInPolicy = (policy: Policy, damages: { itemType: string; amount: number }[]): string | undefined => {
36	  for (const damage of damages) {
37	    if (!policy.items.some((item) => item.type === damage.itemType)) {
38	      return damage.itemType;
39	    }
40	  }
41	  return undefined;
42	};
43	
44	const handleClaimStep = (state: ScenarioState, step: ClaimStep): StepResult => {
45	  const policy = state.policies[step.policy];
46	  const unknownDamageType = findDamageNotInPolicy(policy, step.incident.damages);
47	  if (unknownDamageType !== undefined) {
48	    process.stderr.write(`error: damage itemType "${unknownDamageType}" not in policy\n`);
49	    process.exit(1);
50	  }
51	  const result = claim({ policy, incident: step.incident });
52	  policy.remainingCap = result.remainingCap;
53	  return { payout: result.payout, remainingCap: result.remainingCap };
54	};
55	
56	const processStep = (state: ScenarioState, step: Step): StepResult =>
57	  step.op === "quote" ? handleQuoteStep(state, step) : handleClaimStep(state, step);
58	
59	const runScenario = (scenario: Scenario): StepResult[] => {
60	  const state: ScenarioState = {
61	    customer: scenario.customer,
62	    policies: [],
63	    previousContracts: 0,
64	  };
65	  return scenario.steps.map((step) => processStep(state, step));
66	};
67	
68	const findUnknownItemType = (scenario: Scenario): string | undefined => {
69	  for (const step of scenario.steps) {
70	    if (step.op !== "quote") continue;
71	    for (const item of step.items) {
72	      if (!isKnownItemType(item.type)) return item.type;
73	    }
74	  }
75	  return undefined;
76	};
77	
78	const scenario: Scenario = JSON.parse(readFileSync(0, "utf-8"));
79	
80	const unknownType = findUnknownItemType(scenario);
81	if (unknownType !== undefined) {
82	  process.stderr.write(`error: unknown item type "${unknownType}"\n`);
83	  process.exit(1);
84	}
85	
86	process.stdout.write(JSON.stringify({ results: runScenario(scenario) }));
