const findExcessDamageType = (policy: Policy, damages: { itemType: string; amount: number }[]): string | undefined => {
  const damageCounts = new Map<string, number>();
  for (const damage of damages) {
    damageCounts.set(damage.itemType, (damageCounts.get(damage.itemType) ?? 0) + 1);
  }
  for (const [type, count] of damageCounts) {
    const policyCount = policy.items.filter((item) => item.type === type).length;
    if (count > policyCount) return type;
  }
  return undefined;
};

const handleClaimStep = (state: ScenarioState, step: ClaimStep): StepResult => {
  const policy = state.policies[step.policy];
  const unknownDamageType = findDamageNotInPolicy(policy, step.incident.damages);
  if (unknownDamageType !== undefined) {
    process.stderr.write(`error: damage itemType "${unknownDamageType}" not in policy\n`);
    process.exit(1);
  }
  const excessType = findExcessDamageType(policy, step.incident.damages);
  if (excessType !== undefined) {
    process.stderr.write(`error: more damages of type "${excessType}" than insured\n`);
    process.exit(1);
  }
  const result = claim({ policy, incident: step.incident });
